using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from other tests (shared static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        #region SendNotification

        [Fact]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            _service.SendNotification("Course", "101", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 101", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _service.SendNotification("Department", "5", "Math", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "has been created")]
        [InlineData(EntityOperation.UPDATE, "has been updated")]
        [InlineData(EntityOperation.DELETE, "has been deleted")]
        public void SendNotification_GeneratesCorrectMessage(EntityOperation operation, string expectedFragment)
        {
            _service.SendNotification("Test", "1", "TestEntity", operation, "User");

            var notification = _service.ReceiveNotification();
            Assert.Contains(expectedFragment, notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_CreateMessage_IncludesNew()
        {
            _service.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.StartsWith("New", notification.Message);
        }

        #endregion

        #region ReceiveNotification

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _service.ReceiveNotification();

            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            _service.SendNotification("A", "1", "First", EntityOperation.CREATE);
            _service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Fact]
        public void ReceiveNotification_AfterReceive_MessageIsRemoved()
        {
            _service.SendNotification("Test", "1", EntityOperation.CREATE);

            _service.ReceiveNotification(); // consume
            var result = _service.ReceiveNotification();

            Assert.Null(result);
        }

        #endregion

        #region MarkAsRead

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation but should not throw
            var exception = Record.Exception(() => _service.MarkAsRead(42));
            Assert.Null(exception);
        }

        #endregion

        #region Dispose

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        #endregion
    }
}

using Xunit;

namespace ContosoUniversity.Tests.Helpers
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result[0]);
            Assert.Equal(10, result[9]);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(11, result[0]);
            Assert.Equal(20, result[9]);
        }

        [Fact]
        public void Create_LastPage_MayHaveFewerItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(21, result[0]);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void TotalPages_ExactDivision_NoExtraPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(2, result.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void PageIndex_IsSetCorrectly()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Create_SingleItemOnPage_WorksCorrectly()
        {
            var source = new[] { 42 }.AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Single(result);
            Assert.Equal(42, result[0]);
            Assert.Equal(1, result.TotalPages);
        }
    }
}

