        }

        [Fact]
        public void Index_DateDescSort_ReturnsStudentsOrderedByDateDesc()
        {
            SeedStudents(
                CreateStudent("Alice", "A", new DateTime(2022, 1, 1)),
                CreateStudent("Bob", "B", new DateTime(2023, 9, 1)));

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("B", model[0].LastName); // Later date first
            Assert.Equal("A", model[1].LastName);
