                new DefaultHttpContext(), new Mock<ITempDataProvider>().Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void GetNotifications_ReturnsJsonWithSuccessTrue()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            // JsonResult contains an anonymous object with success property
            var value = result.Value;
            Assert.NotNull(value);
            var successProp = value.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.Equal(true, successProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_WithPendingNotifications_ReturnsNotifications()
        {
            // Enqueue a notification via the base controller's notification service
            var notificationService = new NotificationService();
            notificationService.SendNotification("Test", "1", "Test Entity", EntityOperation.CREATE, "User1");

            // The notifications controller has its own NotificationService instance,
            // but since NotificationService uses a static queue, we can read from any instance
            var result = _controller.GetNotifications();

            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            var count = (int)countProp.GetValue(value);
            Assert.True(count >= 1);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.Equal(true, successProp.GetValue(value));
        }
    }
