using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new StudentsController(_context);
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), Mock.Of<ITempDataProvider>());
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Student CreateStudent(string first = "John", string last = "Doe", DateTime? date = null)
        {
            return new Student
            {
                FirstMidName = first,
                LastName = last,
                EnrollmentDate = date ?? new DateTime(2023, 9, 1)
            };
        }

        private void SeedStudents(params Student[] students)
        {
            _context.Students.AddRange(students);
            _context.SaveChanges();
        }

        #region Index

        [Fact]
        public void Index_NoParams_ReturnsViewWithStudentsOrderedByLastName()
        {
            SeedStudents(
                CreateStudent("Alice", "Zebra"),
                CreateStudent("Bob", "Adams"));

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(2, model.Count);
            Assert.Equal("Adams", model[0].LastName);
            Assert.Equal("Zebra", model[1].LastName);
        }

        [Fact]
        public void Index_NameDescSort_ReturnsStudentsDescending()
        {
            SeedStudents(
                CreateStudent("Alice", "Adams"),
                CreateStudent("Bob", "Zebra"));

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Zebra", model[0].LastName);
            Assert.Equal("Adams", model[1].LastName);
        }

        [Fact]
        public void Index_DateSort_ReturnsStudentsOrderedByDate()
        {
            SeedStudents(
                CreateStudent("Alice", "A", new DateTime(2023, 9, 1)),
                CreateStudent("Bob", "B", new DateTime(2022, 1, 1)));

            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("B", model[0].LastName); // Earlier date first
            Assert.Equal("A", model[1].LastName);
        }

        [Fact]
        public void Index_DateDescSort_ReturnsStudentsOrderedByDateDesc()
        {
            SeedStudents(
                CreateStudent("Alice", "A", new DateTime(2022, 1, 1)),
                CreateStudent("Bob", "B", new DateTime(2023, 9, 1)));

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("B", model[0].LastName); // Later date first
            Assert.Equal("A", model[1].LastName);
        }

        [Fact]
        public void Index_SearchString_FiltersStudentsByLastName()
        {
            SeedStudents(
                CreateStudent("Alice", "Smith"),
                CreateStudent("Bob", "Jones"));

            var result = _controller.Index(null, null, "Smith", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Smith", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_FiltersStudentsByFirstName()
        {
            SeedStudents(
                CreateStudent("Alice", "Smith"),
                CreateStudent("Bob", "Jones"));

            var result = _controller.Index(null, null, "Alice", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alice", model[0].FirstMidName);
        }

        [Fact]
        public void Index_NewSearchString_ResetsPageToOne()
        {
            SeedStudents(CreateStudent());

            _controller.Index(null, null, "test", 5);

            // When searchString is not null, page is reset to 1
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            SeedStudents(CreateStudent("Alice", "Smith"));

            var result = _controller.Index(null, "Smith", null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            SeedStudents(CreateStudent());

            _controller.Index("Date", null, null, null);

            Assert.Equal("Date", _controller.ViewBag.CurrentSort);
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var student = CreateStudent();
            student.Enrollments = new List<Enrollment>();
            SeedStudents(student);

            var result = _controller.Details(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("John", model.FirstMidName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithStudentHavingTodayDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = CreateStudent();

            var result = _controller.Create(student);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_AddsToDatabase()
        {
            var student = CreateStudent("Jane", "Smith");

            _controller.Create(student);

            Assert.Equal(1, _context.Students.Count());
            Assert.Equal("Jane", _context.Students.First().FirstMidName);
        }

        [Fact]
        public void Create_Post_DefaultDate_AddsModelError()
        {
            var student = CreateStudent();
            student.EnrollmentDate = DateTime.MinValue;

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_DateBeforeSqlMin_AddsModelError()
        {
            var student = CreateStudent();
            student.EnrollmentDate = new DateTime(1752, 12, 31);

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var student = CreateStudent();
            _controller.ModelState.AddModelError("LastName", "Required");

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var student = CreateStudent();
            SeedStudents(student);

            var result = _controller.Edit(student.ID) as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Student>(result.Model);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = CreateStudent();
            SeedStudents(student);
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updated = new Student
            {
                ID = student.ID,
                FirstMidName = "Updated",
                LastName = "Name",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Edit(updated);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_DefaultDate_AddsModelError()
        {
            var student = CreateStudent();
            student.EnrollmentDate = default;

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            var student = CreateStudent();
            _controller.ModelState.AddModelError("LastName", "Required");

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var student = CreateStudent();
            SeedStudents(student);

            var result = _controller.Delete(student.ID) as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Student>(result.Model);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
        {
            var student = CreateStudent();
            SeedStudents(student);

            var result = _controller.DeleteConfirmed(student.ID);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(0, _context.Students.Count());
        }

        [Fact]
        public void DeleteConfirmed_InvalidId_RedirectsWithError()
        {
            // When Find returns null, it throws, gets caught, and redirects
            SeedStudents(CreateStudent());

            var result = _controller.DeleteConfirmed(999);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        #endregion
    }

    // Minimal Moq usage for ITempDataProvider
    internal static class Mock
    {
        public static T Of<T>() where T : class
        {
            return new Moq.Mock<T>().Object;
        }
    }
}

