using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new DepartmentsController(_context);
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), new Mock<ITempDataProvider>().Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Department CreateDepartment(string name = "Engineering", decimal budget = 100000m)
        {
            return new Department
            {
                Name = name,
                Budget = budget,
                StartDate = new DateTime(2020, 1, 1)
            };
        }

        private Instructor CreateInstructor(string first = "Dr", string last = "Smith")
        {
            var instructor = new Instructor
            {
                FirstMidName = first,
                LastName = last,
                HireDate = new DateTime(2015, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
            return instructor;
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var dept = CreateDepartment("Mathematics");
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Mathematics", model[0].Name);
        }

        [Fact]
        public void Index_NoDepartments_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;

            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var dept = CreateDepartment("Physics");
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var result = _controller.Details(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("Physics", model.Name);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorSelectList()
        {
            CreateInstructor();

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = CreateDepartment("Chemistry");

            var result = _controller.Create(dept);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_SavesInDatabase()
        {
            var dept = CreateDepartment("Biology");

            _controller.Create(dept);

            Assert.Equal(1, _context.Departments.Count());
            Assert.Equal("Biology", _context.Departments.First().Name);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var dept = CreateDepartment();
            _controller.ModelState.AddModelError("Name", "Required");

            var result = _controller.Create(dept) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            var dept = CreateDepartment("Art");
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var result = _controller.Edit(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("Art", model.Name);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = CreateDepartment("History");
            _context.Departments.Add(dept);
            _context.SaveChanges();
            _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updated = new Department
            {
                DepartmentID = dept.DepartmentID,
                Name = "Modern History",
                Budget = 200000,
                StartDate = new DateTime(2021, 1, 1)
            };

            var result = _controller.Edit(updated);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            var dept = CreateDepartment();
            _controller.ModelState.AddModelError("Name", "Required");

            var result = _controller.Edit(dept) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            var dept = CreateDepartment("Linguistics");
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var result = _controller.Delete(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("Linguistics", model.Name);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesDepartmentAndRedirects()
        {
            var dept = CreateDepartment("Temp Dept");
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(dept.DepartmentID);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Departments.Find(dept.DepartmentID));
        }

        #endregion
    }
}

