using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new InstructorsController(_context);
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), new Mock<ITempDataProvider>().Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Instructor CreateInstructor(string first = "John", string last = "Smith",
            DateTime? hireDate = null, List<CourseAssignment> courses = null)
        {
            return new Instructor
            {
                FirstMidName = first,
                LastName = last,
                HireDate = hireDate ?? new DateTime(2015, 8, 1),
                CourseAssignments = courses ?? new List<CourseAssignment>()
            };
        }

        private void SeedInstructor(Instructor instructor)
        {
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
        }

        #region Index

        [Fact]
        public void Index_NoParams_ReturnsViewWithInstructorData()
        {
            var instructor = CreateInstructor();
            SeedInstructor(instructor);

            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Single(model.Instructors);
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var dept = new Department
            {
                Name = "CS",
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 101,
                Title = "Intro CS",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var instructor = CreateInstructor();
            instructor.CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = 101 }
            };
            SeedInstructor(instructor);

            var result = _controller.Index(instructor.ID, null) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = CreateInstructor("Jane", "Doe");
            SeedInstructor(instructor);

            var result = _controller.Details(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Jane", model.FirstMidName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = CreateInstructor("New", "Prof");

            var result = _controller.Create(instructor, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidInstructorWithCourses_SavesCourseAssignments()
        {
            var dept = new Department
            {
                Name = "Math",
                Budget = 50000,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 201,
                Title = "Calculus",
                Credits = 4,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var instructor = CreateInstructor("New", "Prof");

            _controller.Create(instructor, new[] { "201" });

            var saved = _context.Instructors.First(i => i.LastName == "Prof");
            Assert.NotNull(saved);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var instructor = CreateInstructor();
            _controller.ModelState.AddModelError("LastName", "Required");

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = CreateInstructor("Edit", "Me");
            SeedInstructor(instructor);

            var result = _controller.Edit(instructor.ID) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = CreateInstructor("Del", "Me");
            SeedInstructor(instructor);

            var result = _controller.Delete(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Del", model.FirstMidName);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            var instructor = CreateInstructor("Remove", "Me");
            SeedInstructor(instructor);

            var result = _controller.DeleteConfirmed(instructor.ID);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Instructors.Find(instructor.ID));
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            var instructor = CreateInstructor("Admin", "Instructor");
            SeedInstructor(instructor);

            var dept = new Department
            {
                Name = "Managed Dept",
                Budget = 50000,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = instructor.ID
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }

        #endregion
    }
}

