using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests : IDisposable
    {
        private readonly SchoolContext _context;

        public DbInitializerTests()
        {
            _context = TestDbContextFactory.Create();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsStudents()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(8, _context.Students.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsInstructors()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(5, _context.Instructors.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsDepartments()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(4, _context.Departments.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsCourses()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(7, _context.Courses.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsEnrollments()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(11, _context.Enrollments.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(3, _context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsCourseAssignments()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(8, _context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_AlreadySeeded_DoesNotDuplicate()
        {
            DbInitializer.Initialize(_context);
            var studentCountBefore = _context.Students.Count();

            DbInitializer.Initialize(_context);

            Assert.Equal(studentCountBefore, _context.Students.Count());
        }

        [Fact]
        public void Initialize_SetsStudentProperties()
        {
            DbInitializer.Initialize(_context);

            var student = _context.Students.First(s => s.LastName == "Alexander");
            Assert.Equal("Carson", student.FirstMidName);
            Assert.Equal(new DateTime(2010, 9, 1), student.EnrollmentDate);
        }

        [Fact]
        public void Initialize_SetsInstructorProperties()
        {
            DbInitializer.Initialize(_context);

            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
            Assert.Equal("Kim", instructor.FirstMidName);
            Assert.Equal(new DateTime(1995, 3, 11), instructor.HireDate);
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        #region Person / FullName

        [Fact]
        public void Person_FullName_ReturnsLastCommaFirst()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = "Doe",
                EnrollmentDate = DateTime.Now
            };

            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void Instructor_FullName_ReturnsLastCommaFirst()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                LastName = "Smith",
                HireDate = DateTime.Now
            };

            Assert.Equal("Smith, Jane", instructor.FullName);
        }

        #endregion

        #region Course

        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 101,
                Title = "Intro to CS",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/test.jpg"
            };

            Assert.Equal(101, course.CourseID);
            Assert.Equal("Intro to CS", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/images/test.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_Collections_CanBeInitialized()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Test",
                Credits = 1,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            Assert.Empty(course.Enrollments);
            Assert.Empty(course.CourseAssignments);
        }

        #endregion

        #region Department

        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "CS",
                Budget = 500000m,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = 5,
                RowVersion = new byte[] { 1, 2, 3 }
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("CS", dept.Name);
            Assert.Equal(500000m, dept.Budget);
            Assert.Equal(new DateTime(2020, 1, 1), dept.StartDate);
            Assert.Equal(5, dept.InstructorID);
            Assert.Equal(new byte[] { 1, 2, 3 }, dept.RowVersion);
        }

        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var dept = new Department
            {
                Name = "Test",
                Budget = 0,
                StartDate = DateTime.Now,
                InstructorID = null
            };

            Assert.Null(dept.InstructorID);
        }

        #endregion

        #region Enrollment

        [Fact]
        public void Enrollment_Properties_SetCorrectly()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 101,
                StudentID = 5,
                Grade = Grade.A
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(101, enrollment.CourseID);
            Assert.Equal(5, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 101,
                StudentID = 5,
                Grade = null
            };

            Assert.Null(enrollment.Grade);
        }

        #endregion

        #region Notification

        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New Student created",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New Student created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Notification_ReadAt_CanBeSet()
        {
            var readTime = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Test",
                EntityId = "1",
                Operation = "UPDATE",
                Message = "Updated",
                CreatedAt = DateTime.Now,
                IsRead = true,
                ReadAt = readTime
            };

            Assert.True(notification.IsRead);
            Assert.Equal(readTime, notification.ReadAt);
        }

        #endregion

        #region OfficeAssignment

        [Fact]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var assignment = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Building A, Room 101"
            };

            Assert.Equal(1, assignment.InstructorID);
            Assert.Equal("Building A, Room 101", assignment.Location);
        }

        #endregion

        #region CourseAssignment

        [Fact]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 101
            };

            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(101, ca.CourseID);
        }

        #endregion

        #region AssignedCourseData

        [Fact]
        public void AssignedCourseData_Properties_SetCorrectly()
        {
            var data = new AssignedCourseData
            {
                CourseID = 101,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(101, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        #endregion

        #region InstructorIndexData

        [Fact]
        public void InstructorIndexData_Properties_SetCorrectly()
        {
            var data = new InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.Empty(data.Instructors);
            Assert.Empty(data.Courses);
            Assert.Empty(data.Enrollments);
        }

        #endregion

        #region EnrollmentDateGroup

        [Fact]
        public void EnrollmentDateGroup_Properties_SetCorrectly()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = new DateTime(2023, 9, 1),
                StudentCount = 15
            };

            Assert.Equal(new DateTime(2023, 9, 1), group.EnrollmentDate);
            Assert.Equal(15, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_EnrollmentDate_CanBeNull()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = null,
                StudentCount = 0
            };

            Assert.Null(group.EnrollmentDate);
        }

        #endregion

        #region ErrorViewModel

        [Fact]
        public void ErrorViewModel_Properties_SetCorrectly()
        {
            var model = new ErrorViewModel
            {
                RequestId = "abc123"
            };

            Assert.Equal("abc123", model.RequestId);
            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_NullRequestId_ShowRequestIdFalse()
        {
            var model = new ErrorViewModel
            {
                RequestId = null
            };

            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_EmptyRequestId_ShowRequestIdFalse()
        {
            var model = new ErrorViewModel
            {
                RequestId = ""
            };

            Assert.False(model.ShowRequestId);
        }

        #endregion

        #region EntityOperation Enum

        [Theory]
        [InlineData(EntityOperation.CREATE, "CREATE")]
        [InlineData(EntityOperation.UPDATE, "UPDATE")]
        [InlineData(EntityOperation.DELETE, "DELETE")]
        public void EntityOperation_ToString_ReturnsExpectedValue(EntityOperation op, string expected)
        {
            Assert.Equal(expected, op.ToString());
        }

        #endregion

        #region Grade Enum

        [Theory]
        [InlineData(Grade.A, 0)]
        [InlineData(Grade.B, 1)]
        [InlineData(Grade.C, 2)]
        [InlineData(Grade.D, 3)]
        [InlineData(Grade.F, 4)]
        public void Grade_HasExpectedIntegerValue(Grade grade, int expected)
        {
            Assert.Equal(expected, (int)grade);
        }

        #endregion
    }
}

