    var course = CreateCourse(5003, "Test", dept.DepartmentID);
    _context.Courses.Add(course);
    _context.SaveChanges();
    _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

    var updatedCourse = new Course
    {
        CourseID = 5003,
        Title = "Test",
        Credits = 3,
        DepartmentID = dept.DepartmentID
    };
    var mockFile = new Mock<IFormFile>();
    mockFile.Setup(f => f.FileName).Returns("test.txt");
    mockFile.Setup(f => f.Length).Returns(1024);

    var result = _controller.Edit(updatedCourse, mockFile.Object) as ViewResult;

    Assert.NotNull(result);
    Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
}

